SELECT COUNT(*) AS report_count
FROM tax_reports
WHERE prepared_by = 0;

SELECT name 
FROM tax_groups 
ORDER BY name;

SELECT total_collected, total_paid
FROM tax_reports
WHERE report_date = '2023-04-30';

SELECT total_collected, total_paid
FROM tax_reports
WHERE report_id = 0;

SELECT MAX(report_date) AS latest_report_date
FROM tax_reports
WHERE tax_group_id = '0';

SELECT name
FROM tax_groups
ORDER BY name;
